UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE CITY1 IN ('Wiblingwerde', 'Breckerfeld') OR CITY2 IN ('Wiblingwerde', 'Breckerfeld');

